# Tests Rcpp Evaluator code with PROTECTION fix and gctorture ON.
# Should get a complex vector of zeros.
library(Rcpp)
gctorture()
dyn.load("testfft.so")
for (i in 2:3) {  # bombs on 1 but not 2 or 3
    print(.Call('testfft', 1:20, getNamespace("stats"), i) - fft(1:20))
}
cat("still here\n")
